# Fix customer ChatPage after accidental invalid content / JSON paste.
# Run from repo root:
# powershell -ExecutionPolicy Bypass -File .\fix_customer_chat_page_after_json_paste.ps1

$ErrorActionPreference = "Stop"

$RepoRoot = (Get-Location).Path
$Target = Join-Path $RepoRoot "apps\customer_app\lib\features\chat\pages\chat_page.dart"

if (!(Test-Path (Split-Path $Target))) {
  New-Item -ItemType Directory -Force -Path (Split-Path $Target) | Out-Null
}

$Encoded = @"

"@

$Bytes = [Convert]::FromBase64String($Encoded.Trim())
$Content = [System.Text.Encoding]::UTF8.GetString($Bytes)

# Write UTF-8 without BOM. This removes any pasted JSON/log text at line 1.
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($Target, $Content, $Utf8NoBom)

Write-Host "Fixed ChatPage:" -ForegroundColor Green
Write-Host $Target

Write-Host ""
Write-Host "First 8 lines now:" -ForegroundColor Cyan
Get-Content -LiteralPath $Target -TotalCount 8

Write-Host ""
Write-Host "Now run:" -ForegroundColor Yellow
Write-Host "flutter analyze"
